// Build post array based on quantity and mode
const quantity = $('Trigger').item.json.quantity || 3;
const mode = $('Trigger').item.json.mode || 'inception';
const topics = [
  'Transformação de negócio com tecnologia',
  'Resultados mensuráveis com automação',
  'Cases de sucesso do mercado',
  'Tendências de marketing digital',
  'Como otimizar sua presença digital'
];

const posts = [];
for (let i = 0; i < quantity; i++) {
  posts.push({
    index: i + 1,
    type: i % 3 === 0 ? 'carousel' : 'image',
    topic: topics[i % topics.length],
    mode: mode,
    cta_target: mode === 'atracao_fatal' ? 'funwheel_url' : null
  });
}

return posts.map(p => ({json: p}));

// Image API stub — Story 4.3 will implement actual image generation
// For now, save image_url as null (prompt is ready for manual use or future automation)
const imagePrompt = $('Designer Image Prompt').item.json.data.prompt;
return [{
  json: {
    image_url: null,  // Story 4.3: call Nano Banana or Kling AI here
    image_prompt: imagePrompt,
    status: 'prompt_ready'
  }
}];

// Aggregate all results
const allItems = $input.all();
return [{
  json: {
    pipeline_complete: true,
    posts_generated: allItems.length,
    client_id: $('Trigger').first().json.client_id,
    project_plan_id: $('Trigger').first().json.project_plan_id,
    status: 'draft'
  }
}];
